{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyPaHJYsmrgAxXcF1iyPvfPw"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"z8G4HQIRn8ho"},"outputs":[],"source":["-- Average PM2.5 by station (worst air quality areas)\n","SELECT stationname,\n","       AVG(CAST(pm25value AS DOUBLE)) AS avg_pm25,  --초미세먼지 지수\n","       AVG(CAST(pm10value AS DOUBLE)) AS avg_pm10   --미세먼지 지수\n","FROM air_quality\n","WHERE pm25value != '-'\n","  AND pm10value != '-'\n","  AND stationname LIKE '%구'\n","GROUP BY stationname\n","ORDER BY avg_pm25 DESC;"]}]}